import { Schema, model, Types } from 'mongoose';
const SavedSearchSchema = new Schema({
  userId: { type: Types.ObjectId, required: true, index: true },
  name: String,
  criteria: Schema.Types.Mixed,
  lastRunAt: Date,
  lastMatchIds: [String]
}, { timestamps: true });
export const SavedSearchModel = model('SavedSearch', SavedSearchSchema);

import { SavedSearchModel } from '../models/saved-search.model';
import { ArticleModel } from '../models/article.model';
import { enqueue } from '../queue/enqueue';

export async function checkSavedSearches() {
  const searches = await SavedSearchModel.find({});
  for (const s of searches) {
    const matches = await ArticleModel.find(s.criteria as Record<string, unknown>).limit(100).lean();
    const ids = matches.map(m => String(m._id));
    const newOnes = ids.filter(id => !s.lastMatchIds.includes(id));
    if (newOnes.length > 0) {
      await enqueue.email({ to: String(s.userId), template: 'saved-search-hits', data: { name: s.name, count: newOnes.length, ids: newOnes } });
    }
    s.lastMatchIds = ids;
    s.lastRunAt = new Date();
    await s.save();
  }
}

import crypto from 'node:crypto';

function canonicalize(value: unknown): unknown {
  if (value === null || typeof value !== 'object') return value;
  if (Array.isArray(value)) return value.map(canonicalize);
  const out: Record<string, unknown> = {};
  for (const k of Object.keys(value).sort()) out[k] = canonicalize((value as Record<string, unknown>)[k]);
  return out;
}

export function cacheKey(prefix: string, params: Record<string, unknown>): string {
  const json = JSON.stringify(canonicalize(params));
  const hash = crypto.createHash('sha256').update(json).digest('base64url').slice(0, 16);
  return `${prefix}:${hash}`;
}

import { Server, Socket } from 'socket.io';
import { ContractModel } from '../models/contract.model';
import { auditLog } from '../services/audit.service';

export function attachSignNamespace(io: Server) {
  const ns = io.of('/sign');
  ns.on('connection', (socket: Socket) => {
    const userId = (socket as any).data.userId as string;
    socket.on('contract:join', (contractId: string) => socket.join(`contract:${contractId}`));
    socket.on('cursor', (contractId: string, pos: { x: number; y: number }) => socket.to(`contract:${contractId}`).emit('cursor', { userId, pos }));
    socket.on('sign:commit', async (contractId: string, signature: { points: { x: number; y: number }[]; party: 'A' | 'B' }) => {
      await ContractModel.updateOne({ _id: contractId }, { $set: { [`signatures.${signature.party}`]: { userId, points: signature.points, at: new Date() } } });
      await auditLog({ actorId: userId, action: 'contract.signed', target: contractId, details: { party: signature.party } });
      ns.to(`contract:${contractId}`).emit('sign:done', { userId, party: signature.party });
    });
  });
}

import { useEffect, useRef, useState } from 'react';
import { io } from 'socket.io-client';

export function Sign({ contractId, party, token }: { contractId: string; party: 'A' | 'B'; token: string }) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const points = useRef<{ x: number; y: number }[]>([]);
  const [peerCursor, setPeerCursor] = useState<{ x: number; y: number } | null>(null);
  const [signed, setSigned] = useState<{ A: boolean; B: boolean }>({ A: false, B: false });
  const socketRef = useRef<ReturnType<typeof io> | null>(null);

  useEffect(() => {
    const socket = io('/sign', { auth: { token } });
    socketRef.current = socket;
    socket.emit('contract:join', contractId);
    socket.on('cursor', ({ pos }: { pos: { x: number; y: number } }) => setPeerCursor(pos));
    socket.on('sign:done', ({ party: p }: { party: 'A' | 'B' }) => setSigned(prev => ({ ...prev, [p]: true })));
    return () => { socket.disconnect(); };
  }, [contractId, token]);

  const onMove = (e: React.MouseEvent) => {
    const pos = { x: e.nativeEvent.offsetX, y: e.nativeEvent.offsetY };
    socketRef.current?.emit('cursor', contractId, pos);
    if (e.buttons === 1) {
      points.current.push(pos);
      const ctx = canvasRef.current?.getContext('2d');
      if (ctx) { ctx.lineTo(pos.x, pos.y); ctx.stroke(); }
    }
  };

  const commit = () => socketRef.current?.emit('sign:commit', contractId, { points: points.current, party });

  return (
    <div className="relative">
      <canvas ref={canvasRef} width={500} height={200} className="border" onMouseDown={(e) => { const ctx = canvasRef.current?.getContext('2d'); ctx?.beginPath(); ctx?.moveTo(e.nativeEvent.offsetX, e.nativeEvent.offsetY); }} onMouseMove={onMove} />
      {peerCursor && <div className="absolute w-2 h-2 bg-blue-500 rounded-full pointer-events-none" style={{ left: peerCursor.x - 4, top: peerCursor.y - 4 }} />}
      <button onClick={commit} disabled={signed[party]} className="px-3 py-1 bg-black text-white rounded mt-2">Sign as {party}</button>
      <div>Status: A {signed.A ? 'signed' : 'pending'}, B {signed.B ? 'signed' : 'pending'}</div>
    </div>
  );
}

import { Canvas, useFrame, useThree } from '@react-three/fiber';
