import * as THREE from 'three';

const WALLS: { x: number; z: number; w: number; d: number }[] = [
  { x: 0, z: -5, w: 10, d: 0.5 },
  { x: 5, z: 0, w: 0.5, d: 10 },
  { x: -5, z: 0, w: 0.5, d: 10 },
  { x: 0, z: 5, w: 10, d: 0.5 }
];

function Walls() {
  return <>{WALLS.map((w, i) => (
    <mesh key={i} position={[w.x, 1, w.z]}>
      <boxGeometry args={[w.w, 2, w.d]} />
      <meshStandardMaterial color="#8b7355" />
    </mesh>
  ))}</>;
}

function collides(next: THREE.Vector3): boolean {
  const r = 0.3;
  for (const w of WALLS) {
    if (next.x + r > w.x - w.w / 2 && next.x - r < w.x + w.w / 2 && next.z + r > w.z - w.d / 2 && next.z - r < w.z + w.d / 2) return true;
  }
  return false;
}

function Player() {
  const { camera } = useThree();
  const keys = useRef<Record<string, boolean>>({});
  useEffect(() => {
    const down = (e: KeyboardEvent) => { keys.current[e.code] = true; };
    const up = (e: KeyboardEvent) => { keys.current[e.code] = false; };
    window.addEventListener('keydown', down);
    window.addEventListener('keyup', up);
    camera.position.set(0, 1.6, 3);
    return () => { window.removeEventListener('keydown', down); window.removeEventListener('keyup', up); };
  }, [camera]);
  useFrame((_state, delta) => {
    const forward = new THREE.Vector3();
    camera.getWorldDirection(forward); forward.y = 0; forward.normalize();
    const right = new THREE.Vector3().crossVectors(forward, camera.up).normalize();
    const speed = 4 * delta;
    const move = new THREE.Vector3();
    if (keys.current['KeyW']) move.add(forward.clone().multiplyScalar(speed));
    if (keys.current['KeyS']) move.add(forward.clone().multiplyScalar(-speed));
    if (keys.current['KeyD']) move.add(right.clone().multiplyScalar(speed));
    if (keys.current['KeyA']) move.add(right.clone().multiplyScalar(-speed));
    const next = camera.position.clone().add(move);
    if (!collides(next)) camera.position.copy(next);
  });
  return null;
}

export function Maze() {
