import { Request, Response, NextFunction } from 'express';
import { redis } from '../infra/redis';

export function idempotency(req: Request, res: Response, next: NextFunction) {
  const key = req.headers['idempotency-key'] as string | undefined;
  if (!key || !req.user) return next();
  const cacheKey = `idem:${req.user.id}:${key}`;
  (async () => {
    const cached = await redis.get(cacheKey);
    if (cached) { const { status, body } = JSON.parse(cached); res.status(status).json(body); return; }
    const origJson = res.json.bind(res);
    res.json = ((body: unknown) => {
      redis.set(cacheKey, JSON.stringify({ status: res.statusCode, body }), { EX: 24 * 3600 }).catch(() => {});
      return origJson(body);
    }) as typeof res.json;
    next();
  })().catch(next);
}

