import { useMutation, useQueryClient, type QueryKey } from '@tanstack/react-query';

export function useOptimisticMutation<TVars, TData, TQueryData>(opts: {
  queryKey: QueryKey;
  mutationFn: (vars: TVars) => Promise<TData>;
  applyOptimistic: (prev: TQueryData | undefined, vars: TVars) => TQueryData;
}) {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: opts.mutationFn,
    onMutate: async (vars) => {
      await qc.cancelQueries({ queryKey: opts.queryKey });
      const prev = qc.getQueryData<TQueryData>(opts.queryKey);
      qc.setQueryData(opts.queryKey, opts.applyOptimistic(prev, vars));
      return { prev };
    },
    onError: (_e, _v, ctx) => { if (ctx) qc.setQueryData(opts.queryKey, (ctx as { prev: TQueryData | undefined }).prev); },
    onSettled: () => qc.invalidateQueries({ queryKey: opts.queryKey })
  });
}

