export const FIELDS = {
  order_total: { type: 'number', aggregations: ['sum','avg'], path: 'total' },
  order_status: { type: 'enum', aggregations: ['count'], path: 'status' },
  customer_country: { type: 'string', aggregations: ['count'], path: 'customer.country' }
} as const;

import { OrderModel } from '../models/order.model';
import { FIELDS } from '../../shared/report-fields';
import type { PipelineStage } from 'mongoose';

export type ReportDef = { groupBy?: keyof typeof FIELDS; metric: keyof typeof FIELDS; aggregation: 'sum' | 'avg' | 'count' };

export async function runReport(def: ReportDef) {
  const metric = FIELDS[def.metric];
  if (!metric || !metric.aggregations.includes(def.aggregation)) throw new Error('INVALID_AGGREGATION');
  const groupBy = def.groupBy ? FIELDS[def.groupBy] : null;
  const pipeline: PipelineStage[] = [];
  if (groupBy) pipeline.push({ $group: { _id: `$${groupBy.path}`, value: def.aggregation === 'count' ? { $sum: 1 } : def.aggregation === 'sum' ? { $sum: `$${metric.path}` } : { $avg: `$${metric.path}` } } });
  else pipeline.push({ $group: { _id: null, value: def.aggregation === 'count' ? { $sum: 1 } : def.aggregation === 'sum' ? { $sum: `$${metric.path}` } : { $avg: `$${metric.path}` } } });
  return OrderModel.aggregate(pipeline);
}

