import { Server, Socket } from 'socket.io';
import { PollModel } from '../models/poll.model';
import { VoteModel } from '../models/vote.model';

export function attachPollNamespace(io: Server) {
  const ns = io.of('/poll');
  ns.on('connection', (socket: Socket) => {
    const userId = (socket as any).data.userId as string;
    const role = (socket as any).data.role as string;
    socket.on('poll:join', async (pollId: string) => {
      socket.join(`poll:${pollId}`);
      const poll = await PollModel.findById(pollId).lean();
      if (!poll) return;
      if (role === 'admin' || poll.revealed) {
        const counts = await VoteModel.aggregate([{ $match: { pollId } }, { $group: { _id: '$option', n: { $sum: 1 } } }]);
        socket.emit('poll:counts', counts);
      }
    });
    socket.on('poll:vote', async (pollId: string, option: string) => {
      try { await VoteModel.create({ pollId, voterId: userId, option }); }
      catch (e) { return; }
      const counts = await VoteModel.aggregate([{ $match: { pollId } }, { $group: { _id: '$option', n: { $sum: 1 } } }]);
      ns.to(`poll:${pollId}`).emit('poll:counts:admin', counts);
      const poll = await PollModel.findById(pollId).lean();
      if (poll?.revealed) ns.to(`poll:${pollId}`).emit('poll:counts', counts);
    });
    socket.on('poll:reveal', async (pollId: string) => {
      if (role !== 'admin') return;
      await PollModel.updateOne({ _id: pollId }, { $set: { revealed: true } });
      const counts = await VoteModel.aggregate([{ $match: { pollId } }, { $group: { _id: '$option', n: { $sum: 1 } } }]);
      ns.to(`poll:${pollId}`).emit('poll:counts', counts);
    });
  });
}

