type Book = { id: string; title: string; color: string };

function BookMesh({ book, x, selectedId, onClick }: { book: Book; x: number; selectedId: string | null; onClick: (id: string) => void }) {
  const ref = useRef<THREE.Mesh>(null);
  const targetZ = useRef(0);
  useFrame(() => {
    if (!ref.current) return;
    targetZ.current = selectedId === book.id ? 0.6 : 0;
    ref.current.position.z += (targetZ.current - ref.current.position.z) * 0.15;
  });
  return (
    <mesh ref={ref} position={[x, 0, 0]} onClick={(e: ThreeEvent<MouseEvent>) => { e.stopPropagation(); onClick(book.id); }}>
      <boxGeometry args={[0.2, 1, 0.7]} />
      <meshStandardMaterial color={book.color} />
    </mesh>
  );
}

export function Bookshelf({ books }: { books: Book[] }) {
