        <Canvas camera={{ position: [0, 1, 3] }}>
          <ambientLight intensity={0.6} />
          <directionalLight position={[5, 10, 5]} intensity={0.7} />
          {books.map((b, i) => <BookMesh key={b.id} book={b} x={(i - books.length / 2) * 0.25} selectedId={selectedId} onClick={setSelectedId} />)}
