import crypto from 'node:crypto';
import { AuditLogModel } from '../models/audit-log.model';

function hashBody(body: Record<string, unknown>, prevHash: string): string {
  return crypto.createHash('sha256').update(prevHash + JSON.stringify(Object.keys(body).sort().reduce<Record<string, unknown>>((a, k) => { a[k] = body[k]; return a; }, {}))).digest('hex');
}

export async function appendAudit(body: Record<string, unknown>) {
  const last = await AuditLogModel.findOne({}).sort({ _id: -1 }).lean();
  const prevHash = last?.selfHash ?? '0'.repeat(64);
  const selfHash = hashBody(body, prevHash);
  await AuditLogModel.create({ ...body, prevHash, selfHash });
}

export async function verifyChain(): Promise<{ ok: boolean; firstBadId?: string }> {
  const cursor = AuditLogModel.find({}).sort({ _id: 1 }).cursor();
  let prev = '0'.repeat(64);
  for await (const log of cursor) {
    const recomputed = hashBody({ ...log.toObject(), prevHash: undefined, selfHash: undefined } as any, prev);
    if (recomputed !== log.selfHash) return { ok: false, firstBadId: String(log._id) };
    prev = log.selfHash;
  }
  return { ok: true };
}

import { useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import { useQuery, useQueryClient } from '@tanstack/react-query';

type Item = { id: string; name: string };

function fetchPage(page: number): Promise<{ items: Item[]; hasNext: boolean }> {
  return fetch(`/api/list?page=${page}`).then(r => r.json());
}

export function List() {
  const [params, setParams] = useSearchParams();
  const page = Number(params.get('page') ?? 0);
  const qc = useQueryClient();
  const { data, isLoading } = useQuery({ queryKey: ['list', page], queryFn: () => fetchPage(page) });

  useEffect(() => {
    if (!data?.hasNext) return;
    const id = (window as { requestIdleCallback?: (cb: () => void) => number }).requestIdleCallback?.(() => qc.prefetchQuery({ queryKey: ['list', page + 1], queryFn: () => fetchPage(page + 1) }));
    return () => { if (id) (window as { cancelIdleCallback?: (id: number) => void }).cancelIdleCallback?.(id); };
  }, [data?.hasNext, page, qc]);

  const setPage = (next: number) => { const n = new URLSearchParams(params); n.set('page', String(next)); setParams(n); };

  if (isLoading) return <div>...</div>;
  return (
    <div>
      <ul>{data?.items.map(i => <li key={i.id}>{i.name}</li>)}</ul>
      <button onClick={() => setPage(page - 1)} disabled={page === 0}>Prev</button>
      <button onClick={() => setPage(page + 1)} disabled={!data?.hasNext}>Next</button>
    </div>
  );
}

