import { Server, Socket } from 'socket.io';
import { redis } from '../infra/redis';

const TTL_S = 60;

export function attachDocLockNamespace(io: Server) {
  const ns = io.of('/doc-lock');
  ns.on('connection', (socket: Socket) => {
    const userId = (socket as any).data.userId as string;
    socket.on('lock:acquire', async (docId: string, ack: (ok: boolean) => void) => {
      const set = await redis.set(`lock:doc:${docId}`, userId, { EX: TTL_S, NX: true });
      if (set === 'OK') { ns.to(`doc:${docId}`).emit('lock:held', { docId, userId }); ack(true); }
      else ack(false);
    });
    socket.on('lock:heartbeat', async (docId: string) => {
      const owner = await redis.get(`lock:doc:${docId}`);
      if (owner === userId) await redis.expire(`lock:doc:${docId}`, TTL_S);
    });
    socket.on('lock:release', async (docId: string) => {
      const owner = await redis.get(`lock:doc:${docId}`);
      if (owner === userId) { await redis.del(`lock:doc:${docId}`); ns.to(`doc:${docId}`).emit('lock:released', { docId }); }
    });
  });
}

