import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, useGLTF } from '@react-three/drei';
import { Suspense, useRef, useState } from 'react';
import * as THREE from 'three';

const LAYERS = ['skin', 'muscle', 'organ', 'skeleton'] as const;

function Model({ targets }: { targets: Record<string, number> }) {
  const { scene } = useGLTF('/anatomy.glb');
  const current = useRef<Record<string, number>>({ skin: 1, muscle: 1, organ: 1, skeleton: 1 });
  useFrame(() => {
    for (const layer of LAYERS) {
      current.current[layer] += ((targets[layer] ?? 1) - current.current[layer]) * 0.1;
      const group = scene.getObjectByName(layer);
      if (group) group.traverse(obj => {
        const m = obj as THREE.Mesh;
        if (!m.isMesh) return;
        const mat = m.material as THREE.Material & { opacity: number; transparent: boolean };
        mat.transparent = true; mat.opacity = current.current[layer];
        m.visible = current.current[layer] > 0.01;
      });
    }
  });
  return <primitive object={scene} />;
}

export function AnatomyView() {
  const [vis, setVis] = useState<Record<string, number>>({ skin: 1, muscle: 1, organ: 1, skeleton: 1 });
  return (
    <div className="flex h-screen">
      <div className="flex-1">
        <Canvas><ambientLight intensity={0.6} /><directionalLight position={[5, 10, 5]} intensity={0.7} /><Suspense fallback={null}><Model targets={vis} /></Suspense><OrbitControls /></Canvas>
      </div>
      <aside className="w-56 p-4 bg-white space-y-2">
        {LAYERS.map(l => <label key={l} className="flex items-center gap-2"><input type="range" min={0} max={1} step={0.01} value={vis[l]} onChange={e => setVis(prev => ({ ...prev, [l]: Number(e.target.value) }))} />{l}</label>)}
      </aside>
    </div>
  );
}

