export async function syncUserGroups(orgId: string, userId: string, groups: string[]) {
  const mappings = await GroupRoleMappingModel.find({ orgId, group: { $in: groups } }).lean();
  const roles = Array.from(new Set(mappings.map(m => m.role)));
  const role = roles.includes('admin') ? 'admin' : roles.includes('manager') ? 'manager' : 'viewer';
  const existing = await MembershipModel.findOne({ orgId, userId });
