  await MembershipModel.updateOne({ orgId, userId }, { $set: { role } }, { upsert: true });
}

const inFlight = new Map<string, Promise<unknown>>();

export async function coalesce<T>(key: string, fn: () => Promise<T>): Promise<T> {
  const existing = inFlight.get(key);
  if (existing) return existing as Promise<T>;
  const p = fn().finally(() => inFlight.delete(key));
  inFlight.set(key, p);
  return p;
}

import crypto from 'node:crypto';

export type Experiment = { id: string; variants: { name: string; weight: number }[] };

export function assign(userId: string, exp: Experiment): string {
  const h = crypto.createHash('sha1').update(`${userId}:${exp.id}`).digest();
  const bucket = h.readUInt32BE(0) % 100;
  let acc = 0;
  for (const v of exp.variants) { acc += v.weight; if (bucket < acc) return v.name; }
  return exp.variants.at(-1)!.name;
}

