import { ExperimentEventModel } from '../models/experiment-event.model';

export async function compareVariants(experimentId: string, variantA: string, variantB: string) {
  const eventsA = await ExperimentEventModel.find({ experimentId, variant: variantA }).lean();
  const eventsB = await ExperimentEventModel.find({ experimentId, variant: variantB }).lean();
  const expA = eventsA.filter(e => e.type === 'exposure').length;
  const convA = eventsA.filter(e => e.type === 'conversion').length;
  const expB = eventsB.filter(e => e.type === 'exposure').length;
  const convB = eventsB.filter(e => e.type === 'conversion').length;
  const pA = expA ? convA / expA : 0;
  const pB = expB ? convB / expB : 0;
  const p = (convA + convB) / (expA + expB || 1);
  const se = Math.sqrt(p * (1 - p) * (1 / Math.max(1, expA) + 1 / Math.max(1, expB)));
  const z = se > 0 ? (pB - pA) / se : 0;
  return { variantA: { conversions: convA, exposures: expA, rate: pA }, variantB: { conversions: convB, exposures: expB, rate: pB }, z };
}

import { Request, Response, NextFunction } from 'express';
import { redis } from '../infra/redis';
import { HttpError } from '../errors/http-error';
import { auditLog } from '../services/audit.service';

const BLOCKED_ASNS = new Set(['16509','14618']);
const ALLOWED_ASNS = new Set(['15169','714']);

async function lookupAsn(ip: string): Promise<string | null> {
  const cached = await redis.get(`asn:${ip}`);
  if (cached) return cached;
  try {
    const res = await fetch(`https://api.ipgeolocation.io/asn?ip=${ip}&apiKey=${process.env.IPGEO_KEY}`);
    const data = await res.json() as { as: { number: string } };
    const asn = data.as.number;
    await redis.set(`asn:${ip}`, asn, { EX: 24 * 3600 });
    return asn;
  } catch { return null; }
}

export async function abuseGuard(req: Request, _res: Response, next: NextFunction) {
  try {
    const ip = req.ip ?? '';
    const asn = await lookupAsn(ip);
    if (asn && BLOCKED_ASNS.has(asn) && !ALLOWED_ASNS.has(asn)) {
      await auditLog({ actorId: 'system', action: 'abuse.blocked', target: ip, details: { asn } });
      throw new HttpError(403, 'BLOCKED');
    }
    next();
  } catch (err) { next(err); }
}

export type StateNode<S extends string, E extends string> = { on: Partial<Record<E, S>>; onEntry?: () => void };
export type Machine<S extends string, E extends string> = { initial: S; states: Record<S, StateNode<S, E>> };

import { useReducer } from 'react';

export function useMachine<S extends string, E extends string>(m: Machine<S, E>) {
  const [state, send] = useReducer((current: S, event: E) => {
    const node = m.states[current];
    const next = node.on[event];
    if (!next) return current;
    m.states[next].onEntry?.();
    return next;
  }, m.initial);
  return { state, send };
}

